function solve(grid, x, y, k) {
    // Create a deep copy of the grid to avoid modifying the original directly
    const newGrid = grid.map(row => [...row]);

    // Iterate over each row in the submatrix
    for (let i = 0; i < Math.floor(k / 2); i++) {
        const row1 = x + i;
        const row2 = x + k - 1 - i;

        // Swap the rows within the submatrix columns
        for (let j = y; j < y + k; j++) {
            const temp = newGrid[row1][j];
            newGrid[row1][j] = newGrid[row2][j];
            newGrid[row2][j] = temp;
        }
    }

    return newGrid;
}

